import 'dart:typed_data';

import 'package:flutter_fractals/features/renderer/render_validation.dart';
import 'package:flutter_test/flutter_test.dart';

/// Builds a Uint8List RGBA frame of [w]x[h] pixels, all zeroed (black).
Uint8List _blackFrame(int w, int h) => Uint8List(w * h * 4);

/// Pixel index for (x, y) in a [w]-wide RGBA frame.
int _px(int x, int y, int w) => (y * w + x) * 4;

void main() {
  group('RenderValidationThresholds', () {
    test('exposes default health thresholds as replayable comparisons', () {
      const thresholds = RenderValidationThresholds.defaults;

      expect(thresholds.blackThreshold, 8);
      expect(thresholds.differenceThreshold, 12);
      expect(thresholds.minimumNonBlackRatio, 0.01);
      expect(thresholds.minimumProgressionRatio, 0.002);
      expect(thresholds.minimumIterationDeltaRatio, 0.01);

      expect(thresholds.isNonBlackPixel(8, 8, 8), isFalse);
      expect(thresholds.isNonBlackPixel(9, 0, 0), isTrue);
      expect(
        thresholds.isVisiblyDifferent(
          rA: 0,
          gA: 0,
          bA: 0,
          rB: 4,
          gB: 4,
          bB: 4,
        ),
        isFalse,
      );
      expect(
        thresholds.isVisiblyDifferent(
          rA: 0,
          gA: 0,
          bA: 0,
          rB: 5,
          gB: 4,
          bB: 4,
        ),
        isTrue,
      );
      expect(thresholds.histogramSaneFor(0.01), isFalse);
      expect(thresholds.histogramSaneFor(0.0101), isTrue);
      expect(thresholds.frameProgressedFor(0.002), isFalse);
      expect(thresholds.frameProgressedFor(0.0021), isTrue);
      expect(thresholds.iterationDeltaVisibleFor(0.01), isFalse);
      expect(thresholds.iterationDeltaVisibleFor(0.0101), isTrue);
    });
  });

  group('validateRenderFrame', () {
    test('empty dimensions return invalid black stats instead of crashing', () {
      final stats = validateRenderFrame(
        frame: Uint8List(0),
        width: 0,
        height: 0,
      );

      expect(stats.centerR, 0);
      expect(stats.centerG, 0);
      expect(stats.centerB, 0);
      expect(stats.centerNonBlack, isFalse);
      expect(stats.nonBlackRatio, 0.0);
      expect(stats.histogramSane, isFalse);
    });

    test('negative dimensions are treated as invalid frame geometry', () {
      final frame = _blackFrame(1, 1);
      frame[0] = 80;
      frame[1] = 80;
      frame[2] = 80;

      final stats = validateRenderFrame(
        frame: frame,
        width: -1,
        height: -1,
      );

      expect(stats.centerR, 0);
      expect(stats.centerG, 0);
      expect(stats.centerB, 0);
      expect(stats.centerNonBlack, isFalse);
      expect(stats.nonBlackRatio, 0.0);
      expect(stats.histogramSane, isFalse);
    });

    test('detects all-black frame', () {
      final frame = _blackFrame(4, 4);
      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);

      expect(stats.centerR, 0);
      expect(stats.centerG, 0);
      expect(stats.centerB, 0);
      expect(stats.centerNonBlack, isFalse);
      expect(stats.nonBlackRatio, 0.0);
      expect(stats.histogramSane, isFalse);
    });

    test('detects non-black center pixel', () {
      final frame = _blackFrame(4, 4);
      // center of 4x4 is floor(2), floor(2) = (2,2)
      final idx = _px(2, 2, 4);
      frame[idx] = 100;
      frame[idx + 1] = 150;
      frame[idx + 2] = 200;

      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);

      expect(stats.centerR, 100);
      expect(stats.centerG, 150);
      expect(stats.centerB, 200);
      expect(stats.centerNonBlack, isTrue);
    });

    test('calculates correct nonBlackRatio', () {
      // 8 pixels total; make exactly 4 non-black
      final frame = _blackFrame(4, 2);
      // pixels at (0,0),(1,0),(2,0),(3,0) — first row, r=20 > 8 threshold
      for (int col = 0; col < 4; col++) {
        frame[_px(col, 0, 4)] = 20;
      }
      final stats = validateRenderFrame(frame: frame, width: 4, height: 2);

      expect(stats.nonBlackRatio, closeTo(4 / 8, 1e-9));
    });

    test('histogramSane is false when ratio <= 0.01', () {
      // 100 pixels, only 1 non-black => ratio = 0.01 which is NOT > 0.01
      final frame = _blackFrame(10, 10);
      frame[0] = 20;
      final stats = validateRenderFrame(frame: frame, width: 10, height: 10);

      expect(stats.nonBlackRatio, closeTo(0.01, 1e-9));
      expect(stats.histogramSane, isFalse);
    });

    test('histogramSane is true when ratio > 0.01', () {
      // 100 pixels, 2 non-black => ratio = 0.02 > 0.01
      final frame = _blackFrame(10, 10);
      frame[0] = 20;
      frame[4] = 20; // next pixel (x=1,y=0)
      final stats = validateRenderFrame(frame: frame, width: 10, height: 10);

      expect(stats.nonBlackRatio, closeTo(0.02, 1e-9));
      expect(stats.histogramSane, isTrue);
    });

    test('summary includes backend name', () {
      final frame = _blackFrame(4, 4);
      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);
      final summary = stats.summary('gpu');

      expect(summary, contains('backend=gpu'));
      expect(summary, contains('[renderer]'));
      expect(summary, contains('non_black_ratio='));
      expect(summary, contains('histogram_sane='));
    });

    test('boundary: threshold pixel value of 8 is still counted as black', () {
      final frame = _blackFrame(4, 4);
      // Set center pixel RGB all to exactly 8 — threshold is > 8, so this is black
      final idx = _px(2, 2, 4);
      frame[idx] = 8;
      frame[idx + 1] = 8;
      frame[idx + 2] = 8;

      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);
      expect(stats.centerNonBlack, isFalse);
    });

    test('boundary: pixel value of 9 is counted as non-black', () {
      final frame = _blackFrame(4, 4);
      final idx = _px(2, 2, 4);
      frame[idx] = 9;

      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);
      expect(stats.centerNonBlack, isTrue);
    });
  });

  group('validateRenderPair', () {
    test('empty dimensions return failed check instead of crashing', () {
      final result = validateRenderPair(
        frameA: Uint8List(0),
        frameB: Uint8List(0),
        width: 0,
        height: 0,
      );

      expect(result.centerR, 0);
      expect(result.centerG, 0);
      expect(result.centerB, 0);
      expect(result.centerNonBlack, isFalse);
      expect(result.histogramSane, isFalse);
      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
      expect(result.pass, isFalse);
    });

    test('negative dimensions cannot pass from readable single-pixel frames',
        () {
      final frameA = _blackFrame(1, 1);
      final frameB = _blackFrame(1, 1);
      frameB[0] = 80;
      frameB[1] = 80;
      frameB[2] = 80;

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: -1,
        height: -1,
      );

      expect(result.centerR, 0);
      expect(result.centerG, 0);
      expect(result.centerB, 0);
      expect(result.centerNonBlack, isFalse);
      expect(result.nonBlackRatio, 0.0);
      expect(result.histogramSane, isFalse);
      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
      expect(result.pass, isFalse);
    });

    test('detects frame progression when enough pixels differ', () {
      final frameA = _blackFrame(4, 4);
      final frameB = _blackFrame(4, 4);

      // Make every pixel differ significantly (dr+dg+db > 12)
      for (int i = 0; i < frameB.length; i += 4) {
        frameB[i] = 50;
        frameB[i + 1] = 50;
        frameB[i + 2] = 50;
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 4,
        height: 4,
      );

      expect(result.frameProgressed, isTrue);
      expect(result.iterationDeltaVisible, isTrue);
    });

    test('frameProgressed is false when frames are identical', () {
      final frameA = _blackFrame(4, 4);
      final frameB = Uint8List.fromList(frameA);

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 4,
        height: 4,
      );

      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
    });

    test('iterationDeltaVisible requires > 1% different pixels', () {
      // 100 pixels total; need > 1 different pixel for iterationDeltaVisible
      // Exactly 1 different pixel => 1% which is NOT > 0.01
      final frameA = _blackFrame(10, 10);
      final frameB = Uint8List.fromList(frameA);
      frameB[0] = 100;
      frameB[1] = 100;
      frameB[2] = 100;

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      // progressionRatio = 1/100 = 0.01; frameProgressed needs > 0.002 (true)
      expect(result.frameProgressed, isTrue);
      // iterationDeltaVisible needs > 0.01 (false — exactly 0.01)
      expect(result.iterationDeltaVisible, isFalse);
    });

    test('uses frameB readable pixels for histogram when frameA is truncated',
        () {
      final frameA = _blackFrame(1, 1);
      final frameB = _blackFrame(10, 10);

      for (int i = 0; i < frameB.length; i += 4) {
        frameB[i] = 80;
        frameB[i + 1] = 80;
        frameB[i + 2] = 80;
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      expect(result.nonBlackRatio, 1.0);
      expect(result.histogramSane, isTrue);
      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
    });

    test('does not report progression from incomplete frame pairs', () {
      final frameA = _blackFrame(1, 1);
      final frameB = _blackFrame(1, 1);
      frameB[0] = 80;
      frameB[1] = 80;
      frameB[2] = 80;

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
      expect(result.pass, isFalse);
    });

    test('pass is true only when all checks pass', () {
      // Build a 10x10 frame where enough pixels are non-black and different
      final frameA = _blackFrame(10, 10);
      final frameB = _blackFrame(10, 10);

      // Fill all pixels in frameB with colour that exceeds all thresholds
      for (int i = 0; i < frameB.length; i += 4) {
        frameB[i] = 80;
        frameB[i + 1] = 80;
        frameB[i + 2] = 80;
        frameB[i + 3] = 255;
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      expect(result.centerNonBlack, isTrue);
      expect(result.histogramSane, isTrue);
      expect(result.frameProgressed, isTrue);
      expect(result.iterationDeltaVisible, isTrue);
      expect(result.pass, isTrue);
    });

    test('pass is false when centerNonBlack is false', () {
      // Non-zero progression but center stays black
      final frameA = _blackFrame(10, 10);
      final frameB = _blackFrame(10, 10);

      // Colour many pixels except the center (5,5)
      for (int row = 0; row < 10; row++) {
        for (int col = 0; col < 10; col++) {
          if (row == 5 && col == 5) continue;
          final i = _px(col, row, 10);
          frameB[i] = 80;
          frameB[i + 1] = 80;
          frameB[i + 2] = 80;
        }
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      expect(result.centerNonBlack, isFalse);
      expect(result.pass, isFalse);
    });

    test('handles all-identical frames — no progression', () {
      final frameA = Uint8List.fromList(List.filled(20 * 20 * 4, 50));
      final frameB = Uint8List.fromList(List.filled(20 * 20 * 4, 50));

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 20,
        height: 20,
      );

      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
    });

    test('summary includes pass status and backend name', () {
      final frameA = _blackFrame(4, 4);
      final frameB = _blackFrame(4, 4);
      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 4,
        height: 4,
      );
      final summary = result.summary('cpu');

      expect(summary, contains('backend=cpu'));
      expect(summary, contains('pass='));
      expect(summary, contains('[renderer]'));
    });
  });
}

/// Safe parameter readers for uniform setters.
const double _maxSafeIntegerDouble = 9007199254740991.0;

bool _isSafeIntegerDouble(double value) {
  return value.isFinite && value.abs() <= _maxSafeIntegerDouble;
}

double readDouble(Map<String, Object> params, String key, double fallback) {
  final value = params[key];
  if (value is int) return value.toDouble();
  if (value is double && value.isFinite) return value;
  return fallback;
}

int readInt(Map<String, Object> params, String key, int fallback) {
  final value = params[key];
  if (value is int) return value;
  if (value is double && _isSafeIntegerDouble(value)) return value.round();
  return fallback;
}

import 'package:flutter_test/flutter_test.dart';

import 'package:flutter_fractals/core/modules/param_reader.dart';

void main() {
  group('readDouble', () {
    test('accepts finite int and double values', () {
      expect(readDouble({'power': 8}, 'power', 2.0), 8.0);
      expect(readDouble({'power': 3.5}, 'power', 2.0), 3.5);
    });

    test('falls back for missing, non-numeric, and non-finite values', () {
      expect(readDouble(const {}, 'power', 2.0), 2.0);
      expect(readDouble({'power': '8'}, 'power', 2.0), 2.0);
      expect(readDouble({'power': double.nan}, 'power', 2.0), 2.0);
      expect(readDouble({'power': double.infinity}, 'power', 2.0), 2.0);
      expect(readDouble({'power': double.negativeInfinity}, 'power', 2.0), 2.0);
    });
  });

  group('readInt', () {
    test('accepts integer values and rounds finite doubles', () {
      expect(readInt({'iterations': 120}, 'iterations', 80), 120);
      expect(readInt({'iterations': 120.4}, 'iterations', 80), 120);
      expect(readInt({'iterations': 120.5}, 'iterations', 80), 121);
    });

    test('falls back for missing, non-numeric, and non-finite values', () {
      expect(readInt(const {}, 'iterations', 80), 80);
      expect(readInt({'iterations': '120'}, 'iterations', 80), 80);
      expect(readInt({'iterations': double.nan}, 'iterations', 80), 80);
      expect(readInt({'iterations': double.infinity}, 'iterations', 80), 80);
      expect(readInt({'iterations': double.negativeInfinity}, 'iterations', 80),
          80);
    });

    test('falls back for finite doubles outside integer range', () {
      expect(readInt({'iterations': 1e100}, 'iterations', 80), 80);
      expect(readInt({'iterations': -1e100}, 'iterations', 80), 80);
    });
  });
}

import 'package:flutter_fractals/core/models/export_options.dart';

const int defaultCustomExportWidth = 1920;
const int defaultCustomExportHeight = 1080;

int resolveCustomExportDimension({
  required String fieldText,
  required int? currentValue,
  required int fallback,
}) {
  final parsed = int.tryParse(fieldText.trim());
  if (parsed != null && parsed > 0) return parsed;
  if (currentValue != null && currentValue > 0) return currentValue;
  return fallback;
}

ExportOptions withResolvedCustomExportDimensions({
  required ExportOptions options,
  required String widthText,
  required String heightText,
}) {
  return options.copyWith(
    customWidth: resolveCustomExportDimension(
      fieldText: widthText,
      currentValue: options.customWidth,
      fallback: defaultCustomExportWidth,
    ),
    customHeight: resolveCustomExportDimension(
      fieldText: heightText,
      currentValue: options.customHeight,
      fallback: defaultCustomExportHeight,
    ),
  );
}

import 'package:flutter/foundation.dart';
import 'package:vector_math/vector_math.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/features/history/history_location.dart';

/// Represents a visited location in fractal exploration history.
///
/// Each entry captures the complete state needed to restore a viewpoint:
/// - The fractal module (type) being viewed
/// - The view state (pan, zoom, rotation)
/// - The fractal parameters at that time
/// - Optional metadata like name (for favorites) and timestamp
///
/// {@category Models}
@immutable
class HistoryEntry {
  /// Unique identifier for this history entry.
  final String id;

  /// The fractal module ID (e.g., 'mandelbrot', 'julia').
  final String moduleId;

  /// The view state (pan, zoom, rotation) at this location.
  final FractalViewState view;

  /// The fractal parameters at this location.
  final Map<String, Object> params;

  /// When this location was visited.
  final DateTime visitedAt;

  /// Optional user-defined name for favorites.
  ///
  /// If non-null, this entry is considered a favorite.
  final String? name;

  /// Whether this entry is marked as a favorite.
  bool get isFavorite => name != null;

  /// Creates a new [HistoryEntry].
  const HistoryEntry({
    required this.id,
    required this.moduleId,
    required this.view,
    required this.params,
    required this.visitedAt,
    this.name,
  });

  /// Creates a history entry from the current fractal state.
  factory HistoryEntry.fromState({
    required String moduleId,
    required FractalViewState view,
    required Map<String, Object> params,
    String? name,
  }) {
    return HistoryEntry(
      id: DateTime.now().microsecondsSinceEpoch.toString(),
      moduleId: moduleId,
      view: snapshotHistoryView(view),
      params: snapshotHistoryParams(params),
      visitedAt: DateTime.now(),
      name: name,
    );
  }

  /// Creates a copy with the given fields replaced.
  HistoryEntry copyWith({
    String? id,
    String? moduleId,
    FractalViewState? view,
    Map<String, Object>? params,
    DateTime? visitedAt,
    String? name,
    bool clearName = false,
  }) {
    return HistoryEntry(
      id: id ?? this.id,
      moduleId: moduleId ?? this.moduleId,
      view: view ?? this.view,
      params: params ?? this.params,
      visitedAt: visitedAt ?? this.visitedAt,
      name: clearName ? null : (name ?? this.name),
    );
  }

  /// Serializes this entry to a JSON-compatible map.
  Map<String, Object?> toJson() {
    return {
      'id': id,
      'moduleId': moduleId,
      'view': {
        'panX': view.pan.x,
        'panY': view.pan.y,
        'zoom': view.zoom,
        'rotX': view.rotation.x,
        'rotY': view.rotation.y,
        'rotZ': view.rotation.z,
      },
      'params': params,
      'visitedAt': visitedAt.toIso8601String(),
      'name': name,
    };
  }

  /// Deserializes a history entry from a JSON map.
  static HistoryEntry fromJson(Map<String, Object?> json) {
    final viewJson = json['view'] as Map<String, Object?>? ?? {};
    return HistoryEntry(
      id: json['id'] as String,
      moduleId: json['moduleId'] as String,
      view: FractalViewState(
        pan: Vector2(
          (viewJson['panX'] as num? ?? 0).toDouble(),
          (viewJson['panY'] as num? ?? 0).toDouble(),
        ),
        zoom: (viewJson['zoom'] as num? ?? 1).toDouble(),
        rotation: Vector3(
          (viewJson['rotX'] as num? ?? 0).toDouble(),
          (viewJson['rotY'] as num? ?? 0).toDouble(),
          (viewJson['rotZ'] as num? ?? 0).toDouble(),
        ),
      ),
      params: (json['params'] as Map?)?.map(
            (key, value) => MapEntry(key as String, value as Object),
          ) ??
          {},
      visitedAt: DateTime.tryParse(json['visitedAt'] as String? ?? '') ??
          DateTime.now(),
      name: json['name'] as String?,
    );
  }

  /// Generates a display label for this entry.
  ///
  /// If named, returns the name. Otherwise, returns a
  /// formatted description of the location.
  String get displayLabel {
    if (name != null) return name!;
    final zoomStr = view.zoom >= 10
        ? '${view.zoom.toStringAsFixed(0)}x'
        : '${view.zoom.toStringAsFixed(1)}x';
    return '$moduleId @ $zoomStr';
  }

  /// Checks if this entry represents the same location as another.
  ///
  /// Two entries are at the same location if they have the same
  /// module, view state, and parameters.
  bool isSameLocation(HistoryEntry other) {
    return isSameHistoryLocation(
      moduleId: moduleId,
      view: view,
      params: params,
      otherModuleId: other.moduleId,
      otherView: other.view,
      otherParams: other.params,
    );
  }

  @override
  bool operator ==(Object other) {
    if (identical(this, other)) return true;
    return other is HistoryEntry && other.id == id;
  }

  @override
  int get hashCode => id.hashCode;
}

import 'dart:convert';

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:vector_math/vector_math.dart';

HistoryEntry _entry({
  String moduleId = 'mandelbrot',
  double zoom = 1,
  Map<String, Object> params = const <String, Object>{},
}) {
  return HistoryEntry(
    id: 'entry-$moduleId-$zoom-${params.length}',
    moduleId: moduleId,
    view: FractalViewState(
      pan: Vector2.zero(),
      zoom: zoom,
      rotation: Vector3.zero(),
    ),
    params: params,
    visitedAt: DateTime.utc(2024),
  );
}

void main() {
  group('HistoryEntry location identity', () {
    test('treats matching module, view, and params as the same location', () {
      final first = _entry(params: {'iterations': 100, 'bailout': 4.0});
      final second = _entry(params: {'bailout': 4.0, 'iterations': 100});

      expect(first.isSameLocation(second), isTrue);
    });

    test('treats parameter changes as a different location', () {
      final first = _entry(params: {'iterations': 100});
      final second = _entry(params: {'iterations': 250});

      expect(first.isSameLocation(second), isFalse);
    });

    test('treats JSON-like list parameter values as replayable values', () {
      final first = _entry(params: {
        'paletteStops': [0.0, 0.5, 1.0],
      });
      final second = _entry(params: {
        'paletteStops': [0.0, 0.5, 1.0],
      });

      expect(first.isSameLocation(second), isTrue);
    });

    test('treats view changes as a different location', () {
      final first = _entry(zoom: 1);
      final second = _entry(zoom: 2);

      expect(first.isSameLocation(second), isFalse);
    });

    test('snapshots mutable view vectors and params when created from state',
        () {
      final pan = Vector2(1, 2);
      final rotation = Vector3(3, 4, 5);
      final params = <String, Object>{'iterations': 100};
      final entry = HistoryEntry.fromState(
        moduleId: 'mandelbrot',
        view: FractalViewState(pan: pan, zoom: 6, rotation: rotation),
        params: params,
      );

      pan.setValues(7, 8);
      rotation.setValues(9, 10, 11);
      params['iterations'] = 250;

      expect(entry.view.pan.x, 1);
      expect(entry.view.pan.y, 2);
      expect(entry.view.rotation.x, 3);
      expect(entry.view.rotation.y, 4);
      expect(entry.view.rotation.z, 5);
      expect(entry.params, {'iterations': 100});
    });

    test('serializes nested map parameter keys as JSON object keys', () {
      final entry = HistoryEntry.fromState(
        moduleId: 'mandelbrot',
        view: FractalViewState(
          pan: Vector2.zero(),
          zoom: 6,
          rotation: Vector3.zero(),
        ),
        params: <String, Object>{
          'metadata': <Object, Object>{1: 'one'},
        },
      );

      final encoded = jsonEncode(entry.toJson());
      final decoded = jsonDecode(encoded) as Map<String, Object?>;
      final restored = HistoryEntry.fromJson(decoded);

      expect(restored.params, {
        'metadata': {'1': 'one'},
      });
    });

    test('deep-snapshots nested JSON-like params when created from state', () {
      final paletteStops = <Object?>[
        0.0,
        <String, Object?>{
          'position': 0.5,
          'rgb': <Object?>[32, 64, 128],
        },
        1.0,
      ];
      final params = <String, Object>{'paletteStops': paletteStops};

      final entry = HistoryEntry.fromState(
        moduleId: 'mandelbrot',
        view: FractalViewState(
          pan: Vector2.zero(),
          zoom: 6,
          rotation: Vector3.zero(),
        ),
        params: params,
      );

      (paletteStops[1] as Map<String, Object?>)['position'] = 0.75;
      ((paletteStops[1] as Map<String, Object?>)['rgb'] as List<Object?>)[0] =
          255;
      paletteStops.add(2.0);

      expect(entry.params, {
        'paletteStops': [
          0.0,
          {
            'position': 0.5,
            'rgb': [32, 64, 128],
          },
          1.0,
        ],
      });
    });
  });
}

